// تعريف متغير عالمي لتخزين طلب التثبيت
declare global {
  interface Window {
    deferredPrompt: any;
  }
}

// التقاط حدث التثبيت وتخزينه عالمياً
window.addEventListener('beforeinstallprompt', (e) => {
  // منع النافذة التلقائية المزعجة للتحكم بها يدوياً
  e.preventDefault();
  window.deferredPrompt = e;
  // إعلام التطبيق أن الزر جاهز للعمل فوراً
  window.dispatchEvent(new CustomEvent('pwa-ready-to-install'));
});

// تنظيف الطلب بعد التثبيت
window.addEventListener('appinstalled', () => {
  window.deferredPrompt = null;
  console.log('تم تثبيت التطبيق بنجاح');
});

const rootElement = document.getElementById('root');
