const CACHE_NAME = 'daily-tasks-v6';
const ASSETS_TO_CACHE = [
  '/',
  '/index.html',
  '/manifest.json',
  '/icon.png'
];

self.addEventListener('install', event => {
  event.waitUntil(
    caches.open(CACHE_NAME).then(cache => cache.addAll(ASSETS_TO_CACHE))
  );
  self.skipWaiting();
});

self.addEventListener('activate', event => {
  event.waitUntil(
    caches.keys().then(keys => Promise.all(
      keys.filter(key => key !== CACHE_NAME).map(key => caches.delete(key))
    ))
  );
  self.clients.claim();
});

// ضروري جداً لجعل التطبيق "قابل للتثبيت" في نظر المتصفح
self.addEventListener('fetch', event => {
  // التجاوب مع الطلبات حتى لو كان غير متصل
  event.respondWith(
    caches.match(event.request).then(response => {
      return response || fetch(event.request).catch(() => {
        // إذا فشل كل شيء (أوفلاين)، نرجع الصفحة الرئيسية من الكاش
        if (event.request.mode === 'navigate') {
          return caches.match('/');
        }
      });
    })
  );
});

self.addEventListener('push', event => {
  const data = event.data ? event.data.json() : { title: 'تنبيه', body: 'تحديث جديد في مهامي.' };
  event.waitUntil(self.registration.showNotification(data.title, {
    body: data.body,
    icon: '/icon.png',
    badge: '/icon.png'
  }));
});

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

// تعريف متغير عالمي لتخزين طلب التثبيت
declare global {
  interface Window {
    deferredPrompt: any;
  }
}

// التقاط حدث التثبيت وتخزينه عالمياً بمجرد توفره
window.addEventListener('beforeinstallprompt', (e) => {
  // منع المتصفح من إظهار النافذة التلقائية
  e.preventDefault();
  // تخزين الحدث ليتم استدعاؤه لاحقاً عند ضغط المستخدم على زر التثبيت
  window.deferredPrompt = e;
  // إرسال حدث مخصص لإبلاغ المكونات بأن التثبيت المباشر متاح الآن
  window.dispatchEvent(new CustomEvent('pwa-install-ready'));
  console.log('PWA: Install prompt is ready');
});

// تنظيف المتغير عند نجاح التثبيت
window.addEventListener('appinstalled', () => {
  window.deferredPrompt = null;
  console.log('PWA: App installed successfully');
});

